def offers_wifi(v):
    if v is None:
        return False
    s = str(v).strip().lower().replace("u'", "'")
    s = s.strip('"').strip("'")
    return s not in ('no','none','false','0','')

df_b = df_b[df_b['attributes.WiFi'].apply(offers_wifi)].copy()

out={'cols_after_filter': df_b.columns.tolist(), 'n': int(len(df_b)), 'sample': df_b.head(2).to_dict(orient='records')}
print('__RESULT__:')
print(json.dumps(out))"}

